    67|/**
    68| * A "ghost" milestone directory contains only META.json (and no substantive
    69| * files like CONTEXT, CONTEXT-DRAFT, ROADMAP, or SUMMARY).  These appear when
    70| * a milestone is created but never initialised.  Treating them as active causes
    71| * auto-mode to stall or falsely declare completion.
    72| *
    73| * However, a milestone is NOT a ghost if:
    74| * - It has a DB row with a meaningful status (queued, active, etc.) — the DB
    75| *   knows about it even if content files haven't been created yet.
    76| * - It has a worktree directory — a worktree proves the milestone was
    77| *   legitimately created and is expected to be populated.
    78| *
    79| * Fixes #2921: queued milestones with worktrees were incorrectly classified
    80| * as ghosts, causing auto-mode to skip them entirely.
    81| */
    82|export function isGhostMilestone(basePath: string, mid: string): boolean {
    83|  // If the milestone has a DB row, it's usually a known milestone — not a ghost.
    84|  // Exception: a "queued" row with no disk artifacts is a phantom from
    85|  // gsd_milestone_generate_id that was never planned (#3645).
    86|  if (isDbAvailable()) {
    87|    const dbRow = getMilestone(mid);
    88|    if (dbRow) {
    89|      if (dbRow.status === 'queued') {
    90|        const hasContent = resolveMilestoneFile(basePath, mid, "CONTEXT")
    91|          || resolveMilestoneFile(basePath, mid, "ROADMAP")
    92|          || resolveMilestoneFile(basePath, mid, "SUMMARY");
    93|        return !hasContent;
    94|      }
    95|      return false;
    96|    }
    97|  }
    98|
    99|  // If a worktree exists for this milestone, it was legitimately created.
   100|  const root = gsdRoot(basePath);
   101|  const wtPath = join(root, 'worktrees', mid);
   102|  if (existsSync(wtPath)) return false;
   103|
   104|  // Fall back to content-file check: no substantive files means ghost.
   105|  const context   = resolveMilestoneFile(basePath, mid, "CONTEXT");
   106|  const draft     = resolveMilestoneFile(basePath, mid, "CONTEXT-DRAFT");
   107|  const roadmap   = resolveMilestoneFile(basePath, mid, "ROADMAP");
   108|  const summary   = resolveMilestoneFile(basePath, mid, "SUMMARY");
   109|  return !context && !draft && !roadmap && !summary;
   110|}
   111|
   112|// ─── Query Functions ───────────────────────────────────────────────────────
   113|
   114|/**
   115| * Check if all tasks in a slice plan are done.
   116| */
   117|export function isSliceComplete(plan: SlicePlan): boolean {
   118|  return plan.tasks.length > 0 && plan.tasks.every(t => t.done);
   119|}
   120|
   121|/**
   122| * Check if all slices in a roadmap are done.
   123| */
   124|export function isMilestoneComplete(roadmap: Roadmap): boolean {
   125|  return roadmap.slices.length > 0 && roadmap.slices.every(s => s.done);
   126|}
   127|
   128|/**
   129| * Check whether a VALIDATION file's verdict is terminal.
   130| * Any successfully extracted verdict (pass, needs-attention, needs-remediation,
   131| * fail, etc.) means validation completed. Only return false when no verdict
   132| * could be parsed — i.e. extractVerdict() returns undefined (#2769).
   133| */
   134|export function isValidationTerminal(validationContent: string): boolean {
   135|  return extractVerdict(validationContent) != null;
   136|}
