   138|// ─── State Derivation ──────────────────────────────────────────────────────
   139|
   140|// ── deriveState memoization ─────────────────────────────────────────────────
   141|// Cache the most recent deriveState() result keyed by basePath. Within a single
   142|// dispatch cycle (~100ms window), repeated calls return the cached value instead
   143|// of re-reading the entire .gsd/ tree from disk.
   144|
   145|interface StateCache {
   146|  basePath: string;
   147|  result: GSDState;
   148|  timestamp: number;
   149|}
   150|
   151|const CACHE_TTL_MS = 100;
   152|let _stateCache: StateCache | null = null;
   153|
   154|// ── Telemetry counters for derive-path observability ────────────────────────
   155|let _telemetry = { dbDeriveCount: 0, markdownDeriveCount: 0 };
   156|export function getDeriveTelemetry() { return { ..._telemetry }; }
   157|export function resetDeriveTelemetry() { _telemetry = { dbDeriveCount: 0, markdownDeriveCount: 0 }; }
   158|
   159|/**
   160| * Invalidate the deriveState() cache. Call this whenever planning files on disk
   161| * may have changed (unit completion, merges, file writes).
   162| */
   163|export function invalidateStateCache(): void {
   164|  _stateCache = null;
   165|}
   166|
   167|/**
   168| * Returns the ID of the first incomplete milestone, or null if all are complete.
   169| */
   170|export async function getActiveMilestoneId(basePath: string): Promise<string | null> {
   171|  // Parallel worker isolation
   172|  const milestoneLock = process.env.GSD_MILESTONE_LOCK;
   173|  if (milestoneLock) {
   174|    const milestoneIds = findMilestoneIds(basePath);
   175|    if (!milestoneIds.includes(milestoneLock)) return null;
   176|    const lockedParked = resolveMilestoneFile(basePath, milestoneLock, "PARKED");
   177|    if (lockedParked) return null;
   178|    return milestoneLock;
   179|  }
   180|
   181|  // DB-first: query milestones table for the first non-complete, non-parked milestone
   182|  if (isDbAvailable()) {
   183|    const allMilestones = getAllMilestones();
   184|    if (allMilestones.length > 0) {
   185|      // Respect queue-order.json so /gsd queue reordering is honored (#2556).
   186|      // Without this, the DB path uses lexicographic sort while the dispatch
   187|      // guard uses queue order — causing a deadlock.
   188|      const customOrder = loadQueueOrder(basePath);
   189|      const sortedIds = sortByQueueOrder(allMilestones.map(m => m.id), customOrder);
   190|      const byId = new Map(allMilestones.map(m => [m.id, m]));
   191|      for (const id of sortedIds) {
   192|        const m = byId.get(id)!;
   193|        if (isClosedStatus(m.status) || m.status === "parked") continue;
   194|        return m.id;
   195|      }
   196|      return null;
   197|    }
   198|  }
   199|
   200|  // Filesystem fallback for unmigrated projects or empty DB
