   235|// ── ENCAPSULATION INVARIANT ─────────────────────────────────────────────────
   236|// ALL mutable auto-mode state lives in the AutoSession class (auto/session.ts).
   237|// This file must NOT declare module-level `let` or `var` variables for state.
   238|// The single `s` instance below is the only mutable module-level binding.
   239|//
   240|// When adding features or fixing bugs:
   241|//   - New mutable state → add a property to AutoSession, not a module-level variable
   242|//   - New constants → module-level `const` is fine (immutable)
   243|//   - New state that needs reset on stopAuto → add to AutoSession.reset()
   244|//
   245|// Tests in auto-session-encapsulation.test.ts enforce this invariant.
   246|// ─────────────────────────────────────────────────────────────────────────────
   247|const s = new AutoSession();
   248|
   249|/** Throttle STATE.md rebuilds — at most once per 30 seconds */
   250|const STATE_REBUILD_MIN_INTERVAL_MS = 30_000;
   251|
   252|function captureProjectRootEnv(projectRoot: string): void {
   253|  if (!s.projectRootEnvCaptured) {
   254|    s.hadProjectRootEnv = Object.prototype.hasOwnProperty.call(process.env, "GSD_PROJECT_ROOT");
   255|    s.previousProjectRootEnv = process.env.GSD_PROJECT_ROOT ?? null;
   256|    s.projectRootEnvCaptured = true;
   257|  }
   258|  process.env.GSD_PROJECT_ROOT = projectRoot;
   259|}
   260|
   261|function restoreProjectRootEnv(): void {
   262|  if (!s.projectRootEnvCaptured) return;
   263|
   264|  if (s.hadProjectRootEnv && s.previousProjectRootEnv !== null) {
   265|    process.env.GSD_PROJECT_ROOT = s.previousProjectRootEnv;
   266|  } else {
   267|    delete process.env.GSD_PROJECT_ROOT;
   268|  }
   269|
   270|  s.previousProjectRootEnv = null;
   271|  s.hadProjectRootEnv = false;
   272|  s.projectRootEnvCaptured = false;
   273|}
