   635|      const sid = state.activeSlice!.id;
   636|      const sTitle = state.activeSlice!.title;
   637|      const tid = state.activeTask.id;
   638|
   639|      // Guard: if the slice plan exists but the individual task plan files are
   640|      // missing, the planner created S##-PLAN.md with task entries but never
   641|      // wrote the tasks/ directory files. Dispatch plan-slice to regenerate
   642|      // them rather than hard-stopping — fixes the infinite-loop described in
   643|      // issue #909.
   644|      const taskPlanPath = resolveTaskFile(basePath, mid, sid, tid, "PLAN");
   645|      if (!taskPlanPath || !existsSync(taskPlanPath)) {
   646|        return {
   647|          action: "dispatch",
   648|          unitType: "plan-slice",
   649|          unitId: `${mid}/${sid}`,
   650|          prompt: await buildPlanSlicePrompt(
   651|            mid,
   652|            midTitle,
   653|            sid,
   654|            sTitle,
   655|            basePath,
   656|          ),
   657|        };
   658|      }
   659|
   660|      return null;
   661|    },
   662|  },
   663|  {
   664|    name: "executing → execute-task",
   665|    match: async ({ state, mid, basePath }) => {
   666|      if (state.phase !== "executing" || !state.activeTask) return null;
   667|      if (!state.activeSlice) return missingSliceStop(mid, state.phase);
   668|      const sid = state.activeSlice!.id;
   669|      const sTitle = state.activeSlice!.title;
   670|      const tid = state.activeTask.id;
   671|      const tTitle = state.activeTask.title;
   672|
   673|      return {
   674|        action: "dispatch",
   675|        unitType: "execute-task",
   676|        unitId: `${mid}/${sid}/${tid}`,
   677|        prompt: await buildExecuteTaskPrompt(
   678|          mid,
   679|          sid,
   680|          sTitle,
   681|          tid,
   682|          tTitle,
   683|          basePath,
   684|        ),
   685|      };
   686|    },
   687|  },
   688|  {
   689|    name: "validating-milestone → validate-milestone",
   690|    match: async ({ state, mid, midTitle, basePath, prefs }) => {
   691|      if (state.phase !== "validating-milestone") return null;
   692|
   693|      // Safety guard (#1368): verify all roadmap slices have SUMMARY files before
   694|      // allowing milestone validation.
   695|      const missingSlices = findMissingSummaries(basePath, mid);
   696|      if (missingSlices.length > 0) {
   697|        return {
   698|          action: "stop",
   699|          reason: `Cannot validate milestone ${mid}: slices ${missingSlices.join(", ")} are missing SUMMARY files. These slices may have been skipped.`,
   700|          level: "error",
   701|        };
   702|      }
   703|
   704|      // Skip preference: write a minimal pass-through VALIDATION file
   705|      if (prefs?.phases?.skip_milestone_validation) {
   706|        const mDir = resolveMilestonePath(basePath, mid);
   707|        if (mDir) {
   708|          if (!existsSync(mDir)) mkdirSync(mDir, { recursive: true });
   709|          const validationPath = join(
   710|            mDir,
   711|            buildMilestoneFileName(mid, "VALIDATION"),
   712|          );
   713|          const content = [
   714|            "---",
   715|            "verdict: pass",
   716|            "remediation_round: 0",
   717|            "---",
   718|            "",
   719|            "# Milestone Validation (skipped by preference)",
   720|            "",
   721|            "Milestone validation was skipped via `skip_milestone_validation` preference.",
   722|          ].join("\n");
   723|          writeFileSync(validationPath, content, "utf-8");
   724|        }
   725|        return { action: "skip" };
   726|      }
   727|      return {
   728|        action: "dispatch",
   729|        unitType: "validate-milestone",
   730|        unitId: mid,
   731|        prompt: await buildValidateMilestonePrompt(mid, midTitle, basePath),
   732|      };
   733|    },
   734|  },
   735|  {
   736|    name: "completing-milestone → complete-milestone",
   737|    match: async ({ state, mid, midTitle, basePath }) => {
   738|      if (state.phase !== "completing-milestone") return null;
   739|
   740|      // Safety guard (#2675): block completion when VALIDATION verdict is
   741|      // needs-remediation. The state machine treats needs-remediation as
   742|      // terminal (to prevent validate-milestone loops per #832), but
   743|      // completing-milestone should NOT proceed — remediation work is needed.
   744|      const validationFile = resolveMilestoneFile(basePath, mid, "VALIDATION");
   745|      if (validationFile) {
   746|        const validationContent = await loadFile(validationFile);
   747|        if (validationContent) {
   748|          const verdict = extractVerdict(validationContent);
   749|          if (verdict === "needs-remediation") {
   750|            return {
   751|              action: "stop",
   752|              reason: `Cannot complete milestone ${mid}: VALIDATION verdict is "needs-remediation". Address the remediation findings and re-run validation, or update the verdict manually.`,
   753|              level: "warning",
   754|            };
   755|          }
   756|        }
   757|      }
   758|
   759|      // Safety guard (#1368): verify all roadmap slices have SUMMARY files.
   760|      const missingSlices = findMissingSummaries(basePath, mid);
   761|      if (missingSlices.length > 0) {
   762|        return {
   763|          action: "stop",
   764|          reason: `Cannot complete milestone ${mid}: slices ${missingSlices.join(", ")} are missing SUMMARY files. Run /gsd doctor to diagnose.`,
   765|          level: "error",
   766|        };
   767|      }
   768|
   769|      // Safety guard (#1703): verify the milestone produced implementation
   770|      // artifacts (non-.gsd/ files). A milestone with only plan files and
   771|      // zero implementation code should not be marked complete.
   772|      const artifactCheck = hasImplementationArtifacts(basePath);
   773|      if (artifactCheck === "absent") {
   774|        return {
   775|          action: "stop",
   776|          reason: `Cannot complete milestone ${mid}: no implementation files found outside .gsd/. The milestone has only plan files — actual code changes are required.`,
   777|          level: "error",
   778|        };
   779|      }
   780|      if (artifactCheck === "unknown") {
   781|        logWarning("dispatch", `Implementation artifact check inconclusive for ${mid} — proceeding (git context unavailable)`);
   782|      }
   783|
   784|      // Verification class compliance: if operational verification was planned,
   785|      // ensure the validation output documents it before allowing completion.
   786|      try {
   787|        if (isDbAvailable()) {
   788|          const milestone = getMilestone(mid);
   789|          if (milestone?.verification_operational &&
   790|              !isVerificationNotApplicable(milestone.verification_operational)) {
   791|            const validationPath = resolveMilestoneFile(basePath, mid, "VALIDATION");
   792|            if (validationPath) {
   793|              const validationContent = await loadFile(validationPath);
   794|              if (validationContent) {
   795|                // Allow completion when validation was intentionally skipped by
   796|                // preference/budget profile (#3399, #3344).
   797|                const skippedByPreference = /skip(?:ped)?[\s\-]+(?:by|per|due to)\s+(?:preference|budget|profile)/i.test(validationContent);
   798|
   799|                // Accept either the structured template format (table with MET/N/A/SATISFIED)
   800|                // or prose evidence patterns the validation agent may emit.
   801|                const structuredMatch =
   802|                  validationContent.includes("Operational") &&
   803|                  (validationContent.includes("MET") || validationContent.includes("N/A") || validationContent.includes("SATISFIED"));
   804|                const proseMatch =
   805|                  /[Oo]perational[\s\S]{0,500}?(?:✅|pass|verified|confirmed|met|complete|true|yes|addressed|covered|satisfied|partially|n\/a|not[\s-]+applicable)/i.test(validationContent);
   806|                const hasOperationalCheck = skippedByPreference || structuredMatch || proseMatch;
   807|                if (!hasOperationalCheck) {
   808|                  return {
   809|                    action: "stop" as const,
   810|                    reason: `Milestone ${mid} has planned operational verification ("${milestone.verification_operational.substring(0, 100)}") but the validation output does not address it. Re-run validation with verification class awareness, or update the validation to document operational compliance.`,
   811|                    level: "warning" as const,
   812|                  };
   813|                }
   814|              }
   815|            }
   816|          }
   817|        }
   818|      } catch (err) { /* fall through — don't block on DB errors */
   819|        logWarning("dispatch", `verification class check failed: ${err instanceof Error ? err.message : String(err)}`);
   820|      }
   821|
   822|      return {
   823|        action: "dispatch",
   824|        unitType: "complete-milestone",
   825|        unitId: mid,
   826|        prompt: await buildCompleteMilestonePrompt(mid, midTitle, basePath),
   827|      };
   828|    },
   829|  },
   830|  {
   831|    name: "complete → stop",
   832|    match: async ({ state }) => {
   833|      if (state.phase !== "complete") return null;
   834|      return {
   835|        action: "stop",
   836|        reason: "All milestones complete.",
   837|        level: "info",
   838|      };
   839|    },
   840|  },
   841|];
   842|
   843|import { getRegistry } from "./rule-registry.js";
   844|
   845|// ─── Resolver ─────────────────────────────────────────────────────────────
   846|
   847|/**
   848| * Evaluate dispatch rules in order. Returns the first matching action,
   849| * or a "stop" action if no rule matches (unhandled phase).
   850| *
   851| * Delegates to the RuleRegistry when initialized; falls back to inline
   852| * loop over DISPATCH_RULES for backward compatibility (tests that import
   853| * resolveDispatch directly without registry initialization).
   854| */
   855|export async function resolveDispatch(
   856|  ctx: DispatchContext,
   857|): Promise<DispatchAction> {
   858|  // Delegate to registry when available
   859|  try {
   860|    const registry = getRegistry();
   861|    return await registry.evaluateDispatch(ctx);
   862|  } catch (err) {
   863|    // Registry not initialized — fall back to inline loop
   864|    logWarning("dispatch", `registry dispatch failed, falling back to inline rules: ${err instanceof Error ? err.message : String(err)}`);
   865|  }
   866|
   867|  for (const rule of DISPATCH_RULES) {
   868|    const result = await rule.match(ctx);
   869|    if (result) {
   870|      if (result.action !== "skip") result.matchedRule = rule.name;
   871|      return result;
   872|    }
   873|  }
   874|
   875|  // No rule matched — unhandled phase
   876|  return {
   877|    action: "stop",
   878|    reason: `Unhandled phase "${ctx.state.phase}" — run /gsd doctor to diagnose.`,
   879|    level: "info",
   880|    matchedRule: "<no-match>",
   881|  };
   882|}
   883|
   884|/** Exposed for testing — returns the rule names in evaluation order. */
   885|export function getDispatchRuleNames(): string[] {
   886|  return DISPATCH_RULES.map((r) => r.name);
   887|}
