    38|
    39|/** Wrap a JSON-serializable value as MCP tool content. */
    40|function jsonContent(data: unknown): { content: Array<{ type: 'text'; text: string }> } {
    41|  return { content: [{ type: 'text' as const, text: JSON.stringify(data, null, 2) }] };
    42|}
    43|
    44|/** Return an MCP error response. */
    45|function errorContent(message: string): { isError: true; content: Array<{ type: 'text'; text: string }> } {
    46|  return { isError: true, content: [{ type: 'text' as const, text: message }] };
    47|}
    48|
    49|/** Return raw text content without JSON wrapping. */
    50|function textContent(text: string): { content: Array<{ type: 'text'; text: string }> } {
    51|  return { content: [{ type: 'text' as const, text }] };
