    54|// ---------------------------------------------------------------------------
    55|// gsd_query filesystem reader
    56|// ---------------------------------------------------------------------------
    57|
    58|async function readProjectState(projectDir: string, _query: string): Promise<Record<string, unknown>> {
    59|  const gsdDir = join(resolve(projectDir), '.gsd');
    60|  const result: Record<string, unknown> = { projectDir: resolve(projectDir) };
    61|
    62|  // STATE.md — current execution state
    63|  try {
    64|    result.state = await readFile(join(gsdDir, 'STATE.md'), 'utf-8');
    65|  } catch {
    66|    result.state = null;
    67|  }
    68|
    69|  // PROJECT.md — project description
    70|  try {
    71|    result.project = await readFile(join(gsdDir, 'PROJECT.md'), 'utf-8');
    72|  } catch {
    73|    result.project = null;
    74|  }
    75|
    76|  // REQUIREMENTS.md — requirement contract
    77|  try {
    78|    result.requirements = await readFile(join(gsdDir, 'REQUIREMENTS.md'), 'utf-8');
    79|  } catch {
    80|    result.requirements = null;
    81|  }
    82|
    83|  // List milestones with basic metadata
    84|  const milestonesDir = join(gsdDir, 'milestones');
    85|  try {
    86|    const entries = await readdir(milestonesDir, { withFileTypes: true });
    87|    const milestones: Array<{ id: string; hasRoadmap: boolean; hasSummary: boolean }> = [];
    88|    for (const entry of entries) {
    89|      if (!entry.isDirectory()) continue;
    90|      const mDir = join(milestonesDir, entry.name);
    91|      const hasRoadmap = await fileExists(join(mDir, `${entry.name}-ROADMAP.md`));
    92|      const hasSummary = await fileExists(join(mDir, `${entry.name}-SUMMARY.md`));
    93|      milestones.push({ id: entry.name, hasRoadmap, hasSummary });
    94|    }
    95|    result.milestones = milestones;
    96|  } catch {
    97|    result.milestones = [];
    98|  }
    99|
   100|  return result;
