{"content": "     1|/**
     2| * Orchestrator — LLM-powered agent for the #gsd-control Discord channel.
     3| *
     4| * Receives Discord messages, maintains conversation history, calls the
     5| * Anthropic messages API with 5 tool definitions (list_projects, start_session,
     6| * get_status, stop_session, get_session_detail), and sends the LLM's response
     7| * back to Discord.
     8| *
     9| * Uses the standard messages.create() tool-use loop (not betaZodTool helpers,
    10| * which don't exist in SDK v0.52). Zod schemas are used for input validation
    11| * at the tool execution layer.
    12| */
    13|
    14|import { z } from 'zod';
    15|import type Anthropic from '@anthropic-ai/sdk';
    16|import type {
    17|  MessageParam,
    18|  ContentBlockParam,
    19|  Tool,
    20|  ToolResultBlockParam,
    21|  ToolUseBlock,
    22|  TextBlock,
    23|} from '@anthropic-ai/sdk/resources/messages/messages';
    24|import type { SessionManager } from './session-manager.js';
    25|import type { ChannelManager } from './channel-manager.js';
    26|import type { ProjectInfo, ManagedSession } from './types.js';
    27|import type { Logger } from './logger.js';
    28|
    29|// ---------------------------------------------------------------------------
    30|// API key resolution — requires ANTHROPIC_API_KEY env var
    31|// Anthropic OAuth removed per TOS compliance (see docs/user-docs/claude-code-auth-compliance.md)
    32|// ---------------------------------------------------------------------------
    33|
    34|function resolveAnthropicApiKey(): string {
    35|  const apiKey = process.env.ANTHROPIC_API_KEY;
    36|  if (!apiKey) {
    37|    throw new Error(
    38|      'ANTHROPIC_API_KEY is required. Set it in your environment or run `gsd config`.',
    39|    );
    40|  }
    41|  return apiKey;
    42|}
    43|
    44|// ---------------------------------------------------------------------------
    45|// Configuration
    46|// ---------------------------------------------------------------------------
    47|
    48|export interface OrchestratorConfig {
    49|  model: string;
    50|  max_tokens: number;
    51|  control_channel_id: string;
    52|}
    53|
    54|export interface OrchestratorDeps {
    55|  sessionManager: SessionManager;
    56|  channelManager: ChannelManager;
    57|  scanProjects: () => Promise<ProjectInfo[]>;
    58|  config: OrchestratorConfig;
    59|  logger: Logger;
    60|  ownerId: string;
    61|}
    62|
    63|// ---------------------------------------------------------------------------
    64|// System Prompt
    65|// ---------------------------------------------------------------------------
    66|
    67|const SYSTEM_PROMPT = `You are GSD Control — a concise, capable orchestrator for managing GSD (Get Shit Done) coding agent sessions via Discord.
    68|
    69|You have tools to list projects, start sessions, get status, stop sessions, and inspect session details. Use them to fulfill the user's requests.
