     2| * context-injector.ts — Inject prior step artifacts as context into step prompts.
     3| *
     4| * Reads the frozen DEFINITION.yaml from a run directory, finds the current step's
     5| * `contextFrom` references, locates each referenced step's `produces` artifacts
     6| * on disk, reads their content (truncated to 10k chars), and prepends formatted
     7| * context blocks to the step prompt.
     8| *
     9| * Observability:
    10| * - Truncation is logged via console.warn when it occurs, preventing silent overflow.
    11| * - Missing artifact files are skipped silently (the step may not have produced them yet).
    12| * - Unknown step IDs in contextFrom produce a console.warn for diagnosis.
    13| * - The frozen DEFINITION.yaml on disk is the single source of truth for contextFrom config.
    14| */
    15|
    16|import { readFileSync, existsSync } from "node:fs";
    17|import { join, resolve, sep } from "node:path";
    18|import type { StepDefinition } from "./definition-loader.js";
    19|import { readFrozenDefinition } from "./custom-workflow-engine.js";
    20|
    21|/** Maximum characters per artifact to prevent context window blowout. */
    22|const MAX_CONTEXT_CHARS = 10_000;
    23|
    24|/**
    25| * Inject context from prior step artifacts into a step's prompt.
    26| *
    27| * Reads the frozen DEFINITION.yaml from `runDir`, finds the step matching
    28| * `stepId`, and for each step ID in its `contextFrom` array, looks up that
    29| * step's `produces` paths, reads them from disk (relative to `runDir`),
    30| * truncates to MAX_CONTEXT_CHARS, and prepends as labeled context blocks.
    31| *
    32| * @param runDir — absolute path to the workflow run directory
    33| * @param stepId — the step ID whose prompt to enrich
    34| * @param prompt — the original step prompt
    35| * @returns The prompt with context blocks prepended, or unchanged if no context applies
    36| * @throws Error if DEFINITION.yaml is missing or unreadable
    37| */
    38|export function injectContext(
    39|  runDir: string,
    40|  stepId: string,
    41|  prompt: string,
    42|): string {
    43|  const def = readFrozenDefinition(runDir);
    44|
    45|  const step = def.steps.find((s: StepDefinition) => s.id === stepId);
    46|  if (!step || !step.contextFrom || step.contextFrom.length === 0) {
    47|    return prompt;
    48|  }
    49|
    50|  const contextBlocks: string[] = [];
    51|
    52|  for (const refStepId of step.contextFrom) {
    53|    const refStep = def.steps.find((s: StepDefinition) => s.id === refStepId);
    54|    if (!refStep) {
    55|      console.warn(
    56|        `context-injector: step "${stepId}" references unknown step "${refStepId}" in contextFrom — skipping`,
    57|      );
    58|      continue;
    59|    }
    60|
    61|    if (!refStep.produces || refStep.produces.length === 0) {
    62|      continue;
    63|    }
    64|
    65|    for (const relPath of refStep.produces) {
    66|      const absPath = resolve(runDir, relPath);
    67|      // Path traversal guard: ensure resolved path stays within runDir
    68|      if (!absPath.startsWith(resolve(runDir) + sep) && absPath !== resolve(runDir)) {
    69|        console.warn(
    70|          `context-injector: artifact path "${relPath}" resolves outside runDir — skipping`,
    71|        );
    72|        continue;
    73|      }
    74|      if (!existsSync(absPath)) {
    75|        // Artifact not yet produced or optional — skip silently
    76|        continue;
    77|      }
    78|
    79|      let content = readFileSync(absPath, "utf-8");
    80|
    81|      if (content.length > MAX_CONTEXT_CHARS) {
    82|        console.warn(
    83|          `context-injector: truncating artifact "${relPath}" from step "${refStepId}" ` +
    84|            `(${content.length} chars → ${MAX_CONTEXT_CHARS} chars)`,
    85|        );
    86|        content = content.slice(0, MAX_CONTEXT_CHARS) + "\n...[truncated]";
    87|      }
    88|
    89|      contextBlocks.push(
    90|        `--- Context from step "${refStepId}" (file: ${relPath}) ---\n${content}\n---`,
    91|      );
    92|    }
    93|  }
    94|
    95|  if (contextBlocks.length === 0) {
    96|    return prompt;
    97|  }
    98|
    99|  return contextBlocks.join("\n\n") + "\n\n" + prompt;
